import React, { useState } from 'react';
import { motion } from 'framer-motion';
import { ExternalLink, Trash2, Globe, Edit2, Copy, Check, Share2, GripVertical } from 'lucide-react';
import { useSortable } from '@dnd-kit/sortable';
import { CSS } from '@dnd-kit/utilities';
import { Bookmark } from '../types';
import { getFaviconUrl } from '../utils/helpers';

interface BookmarkCardProps {
  bookmark: Bookmark;
  onDelete: (id: string) => void;
  onEdit: (bookmark: Bookmark) => void;
  isDragOverlay?: boolean;
}

const BookmarkCard: React.FC<BookmarkCardProps> = ({ bookmark, onDelete, onEdit, isDragOverlay = false }) => {
  const [imageError, setImageError] = useState(false);
  const [isCopied, setIsCopied] = useState(false);

  // dnd-kit hook
  const {
    attributes,
    listeners,
    setNodeRef,
    transform,
    transition,
    isDragging,
  } = useSortable({ id: bookmark.id });

  const style = {
    transform: CSS.Transform.toString(transform),
    transition,
    opacity: isDragging ? 0.4 : 1,
    zIndex: isDragging ? 50 : 'auto',
    touchAction: 'none', // Prevents scrolling when dragging via the handle
  };

  const copyToClipboard = () => {
    navigator.clipboard.writeText(bookmark.url).then(() => {
      setIsCopied(true);
      setTimeout(() => setIsCopied(false), 2000);
    }).catch(err => {
      console.error('Failed to copy: ', err);
    });
  };

  const handleCopy = (e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();
    copyToClipboard();
  };

  const handleShare = async (e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();

    if (navigator.share) {
      try {
        await navigator.share({
          title: bookmark.title,
          text: `Check out this link: ${bookmark.title}`,
          url: bookmark.url,
        });
      } catch (err) {
        console.log('Share canceled or failed:', err);
      }
    } else {
      copyToClipboard();
    }
  };

  const handleVisit = (e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();
    window.open(bookmark.url, '_blank', 'noopener,noreferrer');
  };

  // If this is the "Ghost" overlay, we don't want the hook attributes/listeners on it again
  const cardProps = isDragOverlay ? {} : {
    ref: setNodeRef,
    style: style,
    ...attributes
  };

  return (
    <motion.div
      layout={!isDragging} // Disable layout animation while dragging to prevent fighting with DnD
      initial={isDragOverlay ? undefined : { opacity: 0, y: 20 }}
      animate={isDragOverlay ? undefined : { opacity: 1, y: 0 }}
      exit={{ opacity: 0, scale: 0.9 }}
      whileHover={isDragOverlay ? undefined : { y: -2 }}
      className={`group relative w-full ${isDragOverlay ? 'cursor-grabbing scale-105 z-50' : ''}`}
      {...cardProps}
    >
      {/* Material Card - Surface Container Low */}
      <div className={`
        relative overflow-hidden rounded-[16px]
        bg-m3-surfaceContainer-light dark:bg-m3-surfaceContainer-dark
        border border-gray-200 dark:border-gray-700
        transition-shadow duration-300
        h-full flex flex-col
        ${isDragOverlay ? 'shadow-xl' : 'hover:shadow-md shadow-sm'}
      `}>
        {/* Ripple/State Layer on Hover */}
        {!isDragOverlay && (
          <div className="absolute inset-0 bg-current opacity-0 hover:opacity-[0.08] dark:hover:opacity-[0.08] transition-opacity duration-200 pointer-events-none text-indigo-900 dark:text-indigo-100" />
        )}

        <div className="p-4 flex flex-col h-full z-10 relative">
          <div className="flex items-start justify-between mb-3">
            <div className="flex items-center gap-3">
              {/* Drag Handle */}
              {!isDragOverlay && (
                 <div 
                  {...listeners} 
                  className="cursor-grab active:cursor-grabbing p-1.5 -ml-2 rounded-full text-gray-500 hover:bg-gray-200 dark:text-gray-400 dark:hover:bg-gray-700 transition-colors"
                  title="Drag to reorder"
                >
                  <GripVertical size={20} />
                </div>
              )}

              <div className="flex items-center justify-center w-10 h-10 rounded-xl bg-white dark:bg-gray-700 shadow-sm border border-gray-100 dark:border-gray-600">
                {!imageError ? (
                  <img 
                    src={getFaviconUrl(bookmark.domain)} 
                    alt={bookmark.title}
                    className="w-6 h-6 object-contain"
                    onError={() => setImageError(true)}
                  />
                ) : (
                  <Globe className="w-5 h-5 text-gray-500 dark:text-gray-400" />
                )}
              </div>
            </div>

            <div className="flex items-center">
              {/* Actions visible on hover or mobile always accessible via tap target */}
              <motion.button
                whileHover={{ scale: 1.1 }}
                whileTap={{ scale: 0.9 }}
                onClick={handleShare}
                className="p-2 rounded-full hover:bg-gray-200 dark:hover:bg-gray-700 text-gray-500 dark:text-gray-400 transition-colors"
                title="Share"
              >
                <Share2 size={18} />
              </motion.button>

              <motion.button
                whileHover={{ scale: 1.1 }}
                whileTap={{ scale: 0.9 }}
                onClick={handleCopy}
                className="p-2 rounded-full hover:bg-gray-200 dark:hover:bg-gray-700 text-gray-500 dark:text-gray-400 transition-colors"
                title={isCopied ? "Copied!" : "Copy Link"}
              >
                {isCopied ? <Check size={18} className="text-emerald-600" /> : <Copy size={18} />}
              </motion.button>

              <motion.button
                whileHover={{ scale: 1.1 }}
                whileTap={{ scale: 0.9 }}
                onClick={(e) => {
                  e.preventDefault();
                  e.stopPropagation();
                  onEdit(bookmark);
                }}
                className="p-2 rounded-full hover:bg-gray-200 dark:hover:bg-gray-700 text-gray-500 dark:text-gray-400 transition-colors"
                title="Edit Bookmark"
              >
                <Edit2 size={18} />
              </motion.button>

              <motion.button
                whileHover={{ scale: 1.1 }}
                whileTap={{ scale: 0.9 }}
                onClick={(e) => {
                  e.preventDefault();
                  e.stopPropagation();
                  onDelete(bookmark.id);
                }}
                className="p-2 rounded-full hover:bg-red-50 dark:hover:bg-red-900/20 text-gray-500 hover:text-red-600 dark:text-gray-400 dark:hover:text-red-400 transition-colors"
                title="Delete Bookmark"
              >
                <Trash2 size={18} />
              </motion.button>
            </div>
          </div>

          <div className="flex-grow">
            <h3 className="text-base font-medium text-gray-900 dark:text-gray-50 mb-1 line-clamp-1 leading-tight">
              {bookmark.title || bookmark.domain}
            </h3>
            <div className="flex items-center gap-2 mb-1">
              <span className="text-[11px] font-medium px-2 py-0.5 rounded-md bg-indigo-50 text-indigo-700 dark:bg-indigo-900/30 dark:text-indigo-300">
                {bookmark.category}
              </span>
            </div>
            <p className="text-sm text-gray-500 dark:text-gray-400 truncate">
              {bookmark.domain}
            </p>
          </div>

          <div className="mt-4 pt-3 border-t border-gray-200 dark:border-gray-700 flex justify-end">
            <motion.button 
              whileHover={{ scale: 1.02 }}
              whileTap={{ scale: 0.98 }}
              onClick={handleVisit}
              className="
                flex items-center space-x-2 px-4 py-2 rounded-full
                bg-indigo-600 dark:bg-indigo-300
                hover:bg-indigo-700 dark:hover:bg-indigo-200
                text-white dark:text-indigo-900
                font-medium text-sm transition-colors shadow-sm
              "
            >
              <span>Visit Site</span>
              <ExternalLink size={14} />
            </motion.button>
          </div>
        </div>
      </div>
    </motion.div>
  );
};

export default BookmarkCard;

import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { X, Plus, Link as LinkIcon, Type, Loader2, Save, Tag } from 'lucide-react';
import { ensureUrlProtocol, getDomainFromUrl, getCategoryFromDomain } from '../utils/helpers';
import { Bookmark, CategoryType } from '../types';

interface AddBookmarkFormProps {
  isOpen: boolean;
  onClose: () => void;
  onSubmit: (bookmark: Omit<Bookmark, 'id' | 'createdAt'>) => void;
  initialData?: Bookmark | null;
  categories: CategoryType[];
}

const AddBookmarkForm: React.FC<AddBookmarkFormProps> = ({ isOpen, onClose, onSubmit, initialData, categories }) => {
  const [url, setUrl] = useState('');
  const [title, setTitle] = useState('');
  const [category, setCategory] = useState<CategoryType>('Websites');
  const [isSubmitting, setIsSubmitting] = useState(false);

  // Filter out "All Bookmarks" from the selectable options
  const selectableCategories = categories.filter(c => c !== 'All Bookmarks');

  useEffect(() => {
    if (isOpen) {
      if (initialData) {
        setUrl(initialData.url);
        setTitle(initialData.title);
        setCategory(initialData.category);
      } else {
        setUrl('');
        setTitle('');
        setCategory('Websites');
      }
    }
  }, [isOpen, initialData]);

  // Auto-detect category when URL changes, but only if not in edit mode (or if user just cleared it)
  useEffect(() => {
    if (url && !initialData) { 
      const formattedUrl = ensureUrlProtocol(url);
      const domain = getDomainFromUrl(formattedUrl);
      const detectedCategory = getCategoryFromDomain(domain);
      // Only switch if we detect something specific, or if we are just starting
      if (detectedCategory !== 'Websites') {
        setCategory(detectedCategory);
      }
    }
  }, [url, initialData]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!url) return;

    setIsSubmitting(true);

    try {
      const formattedUrl = ensureUrlProtocol(url);
      const domain = getDomainFromUrl(formattedUrl);

      let finalTitle = title.trim();

      // Attempt 1: YouTube specific handling via NoEmbed (oEmbed proxy)
      if (!finalTitle && (domain.includes('youtube.com') || domain.includes('youtu.be'))) {
        try {
          const response = await fetch(`https://noembed.com/embed?url=${encodeURIComponent(formattedUrl)}`);
          const data = await response.json();
          if (data.title) {
            finalTitle = data.title;
          }
        } catch (error) {
          console.warn('NoEmbed fetch failed for YouTube', error);
        }
      }

      // Attempt 2: If title is still empty, try to fetch it from Microlink
      if (!finalTitle) {
        try {
          const response = await fetch(`https://api.microlink.io/?url=${encodeURIComponent(formattedUrl)}`);
          const data = await response.json();
          if (data.status === 'success' && data.data && data.data.title) {
            finalTitle = data.data.title;
          }
        } catch (error) {
          console.warn('Failed to fetch title from Microlink, falling back to domain', error);
        }
      }

      // Fallback if fetch failed or title was still empty
      if (!finalTitle) {
        finalTitle = domain;
      }

      onSubmit({
        url: formattedUrl,
        title: finalTitle,
        domain,
        category: category
      });

      // Reset and close (though parent might handle close)
      if (!initialData) {
          setUrl('');
          setTitle('');
          setCategory('Websites');
      }
      onClose();
    } catch (error) {
      console.error('Error saving bookmark:', error);
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
