                  placeholder-gray-500 dark:placeholder-gray-400 
                  text-sm transition-all
                  text-gray-900 dark:text-white
                "
              />
           </div>
        </div>

        {/* Breadcrumbs - Only show when inside a folder and not searching */}
        {!searchQuery && currentFolderId && (
          <nav className="flex items-center gap-1 mb-3 overflow-x-auto no-scrollbar" aria-label="Breadcrumb">
             <button 
                onClick={() => handleNavigateUp(null)}
                className="flex items-center justify-center p-1.5 rounded-full text-gray-500 dark:text-gray-400 hover:bg-gray-100 dark:hover:bg-gray-800 transition-colors"
                title="Go to Home"
             >
               <Home size={18} />
             </button>

             {breadcrumbs.map((crumb, index) => {
                const isLast = index === breadcrumbs.length - 1;
                return (
                <div key={crumb.id} className="flex items-center flex-shrink-0">
                  <ChevronRight size={14} className="text-gray-300 dark:text-gray-600 mx-0.5" />
                  <button
                    onClick={() => !isLast && handleNavigateUp(crumb.id)}
                    disabled={isLast}
                    className={`
                      text-xs px-3 py-1 rounded-full transition-colors whitespace-nowrap font-medium border
                      ${isLast 
                        ? 'bg-indigo-100 text-indigo-900 border-indigo-200 dark:bg-indigo-900/30 dark:text-indigo-200 dark:border-indigo-800 cursor-default shadow-sm' 
                        : 'bg-transparent text-gray-600 border-gray-300 dark:text-gray-300 dark:border-gray-800 hover:bg-gray-50 dark:hover:bg-gray-800'}
                    `}
                  >
                    {crumb.title}
                  </button>
                </div>
             )})}
          </nav>
        )}

        {/* Third Row: Categories - Scrollable Chips */}
        <div className="flex items-center justify-between pb-2">
           <div className="flex-grow overflow-hidden">
             <CategoryTabs 
               categories={CATEGORIES} 
               selectedCategory={selectedCategory} 
               onSelectCategory={setSelectedCategory} 
             />
           </div>

           {/* Desktop Add Button (Text/Icon style) */}
           <div className="pl-2 hidden md:block">
              <motion.button
               whileHover={{ scale: 1.02 }}
               whileTap={{ scale: 0.95 }}
               onClick={openAddModal}
               className="
                 flex items-center space-x-2 px-4 py-2 rounded-full
                 bg-indigo-600 dark:bg-indigo-300 
                 text-white dark:text-indigo-900 
                 font-medium text-xs
                 hover:bg-indigo-700 dark:hover:bg-indigo-200 
                 transition-colors shadow-sm
               "
             >
               <Plus size={16} />
               <span>New</span>
             </motion.button>
           </div>
        </div>
      </div>

      {/* Scrollable Main Content */}
      <div 
        className="flex-1 overflow-y-auto overflow-x-hidden p-3 sm:px-6 lg:px-8 pb-20 sm:pb-8 scroll-smooth"
        style={{ WebkitOverflowScrolling: 'touch' }}
      >
         <div className="max-w-7xl mx-auto min-h-full">
            {bookmarks.length === 0 ? (
            <div className="flex flex-col items-center justify-center h-64 text-center mt-10">
              <div className="w-16 h-16 bg-indigo-50 dark:bg-indigo-900/20 rounded-full flex items-center justify-center mb-4">
                <LayoutGrid className="w-8 h-8 text-indigo-400 opacity-75" />
              </div>
              <h3 className="text-lg font-normal text-gray-900 dark:text-white mb-1">No bookmarks yet</h3>
              <p className="text-xs text-gray-500 dark:text-gray-400 max-w-xs">
                Start building your collection by adding your first bookmark.
              </p>
              <button 
                onClick={openAddModal}
                className="mt-4 text-indigo-600 dark:text-indigo-300 font-medium text-sm hover:underline"
              >
                Create Bookmark
              </button>
            </div>
          ) : filteredBookmarks.length === 0 ? (
             <div className="flex flex-col items-center justify-center h-64 text-center mt-10">
              {searchQuery ? (
                 <>
                   <Search className="w-10 h-10 text-gray-400 mb-3 opacity-75" />
                   <h3 className="text-base font-normal text-gray-900 dark:text-white">No matches found</h3>
                 </>
              ) : (
                <>
                  <LayoutGrid className="w-10 h-10 text-gray-400 mb-3 opacity-75" />
                  <h3 className="text-base font-normal text-gray-900 dark:text-white">Folder is empty</h3>
                </>
              )}
              <p className="text-xs text-gray-500 dark:text-gray-400 mt-1">
                {searchQuery ? "Try adjusting your search." : "Add a bookmark or folder here."}
              </p>
            </div>
          ) : (
            <DndContext
              sensors={sensors}
              collisionDetection={closestCenter}
              onDragStart={handleDragStart}
              onDragEnd={handleDragEnd}
            >
              <SortableContext 
                items={filteredBookmarks.map(b => b.id)}
                strategy={rectSortingStrategy}
              >
                <motion.div 
                  layout={!activeId}
                  className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-3"
                >
                  <AnimatePresence>
                    {filteredBookmarks.map((bookmark) => (
                      <BookmarkCard 
                        key={bookmark.id} 
                        bookmark={bookmark} 
                        onDelete={handleDeleteClick} 
                        onEdit={openEditModal}
                        onNavigate={handleNavigate}
                      />
                    ))}
                  </AnimatePresence>
                </motion.div>
              </SortableContext>

              <DragOverlay adjustScale={true}>
                {activeBookmark ? (
                  <div className="opacity-90">
                     <BookmarkCard
                        bookmark={activeBookmark}
                        onDelete={() => {}}
                        onEdit={() => {}}
                        onNavigate={() => {}}
                        isDragOverlay
                      />
                  </div>
                ) : null}
              </DragOverlay>
            </DndContext>
          )}
         </div>
      </div>

      {/* Material FAB - Smaller */}
      <motion.button
        initial={{ scale: 0 }}
        animate={{ scale: 1 }}
        whileHover={{ scale: 1.05 }}
        whileTap={{ scale: 0.95 }}
        onClick={openAddModal}
        className="
          md:hidden fixed bottom-5 right-5 z-40 
          w-12 h-12 flex items-center justify-center
          bg-indigo-600 dark:bg-indigo-300 
          text-white dark:text-indigo-900 
          rounded-[14px] shadow-lg hover:shadow-xl
          transition-all
        "
      >
        <Plus size={20} />
      </motion.button>

      <AddBookmarkForm 
        isOpen={isModalOpen} 
        onClose={() => {
          setIsModalOpen(false);
          setEditingBookmark(null);
        }} 
        onSubmit={handleSaveBookmark}
        initialData={editingBookmark}
        categories={CATEGORIES}
      />

      {/* Delete Confirmation Modal */}
      <AnimatePresence>
        {itemToDelete && (
          <>
            <motion.div
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              exit={{ opacity: 0 }}
              onClick={() => setItemToDelete(null)}
              className="fixed inset-0 bg-black/50 z-50"
            />
            <motion.div
              initial={{ opacity: 0, scale: 0.95 }}
              animate={{ opacity: 1, scale: 1 }}
              exit={{ opacity: 0, scale: 0.95 }}
              className="fixed inset-0 z-50 flex items-center justify-center p-4 pointer-events-none"
            >
              <div className="pointer-events-auto w-full max-w-xs bg-m3-surfaceContainer-light dark:bg-m3-surfaceContainer-dark rounded-[24px] p-5 text-center shadow-xl border border-transparent dark:border-gray-800">
                <div className="mx-auto w-10 h-10 bg-red-100 dark:bg-red-900/30 rounded-full flex items-center justify-center mb-3">
                  <Trash2 className="w-5 h-5 text-red-600 dark:text-red-400" />
                </div>
                <h3 className="text-lg font-normal text-gray-900 dark:text-white mb-2">Delete Item?</h3>
                <p className="text-xs text-gray-500 dark:text-gray-400 mb-5">
                  Are you sure you want to delete this? If it's a folder, all contents will be deleted.
                </p>
                <div className="flex gap-2 justify-end">
                  <button
                    onClick={() => setItemToDelete(null)}
                    className="px-3 py-1.5 rounded-full text-indigo-600 dark:text-indigo-300 font-medium text-sm hover:bg-indigo-50 dark:hover:bg-indigo-900/20 transition-colors"
                  >
                    Cancel
                  </button>
                  <button
                    onClick={confirmDelete}
                    className="px-3 py-1.5 rounded-full bg-red-600 text-white font-medium text-sm hover:bg-red-700 transition-colors shadow-sm"
                  >
                    Delete
                  </button>
                </div>
              </div>
            </motion.div>
          </>
        )}
      </AnimatePresence>

      {/* Settings Modal - Material Dialog */}
      <AnimatePresence>
        {isSettingsOpen && (
          <>
            <motion.div
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              exit={{ opacity: 0 }}
              onClick={() => setIsSettingsOpen(false)}
              className="fixed inset-0 bg-black/50 z-40"
            />
            <motion.div
              initial={{ opacity: 0, scale: 0.95, y: 10 }}
              animate={{ opacity: 1, scale: 1, y: 0 }}
              exit={{ opacity: 0, scale: 0.95, y: 10 }}
              className="fixed inset-0 z-50 flex items-center justify-center p-4 pointer-events-none"
            >
              <div className="pointer-events-auto w-full max-w-sm">
                <div className="relative overflow-hidden rounded-[24px] bg-m3-surfaceContainer-light dark:bg-m3-surfaceContainer-dark shadow-2xl p-5 border border-transparent dark:border-gray-800">

                  <div className="flex items-center justify-between mb-5">
                    <h2 className="text-lg font-normal text-gray-900 dark:text-white flex items-center gap-2">
                      <Settings className="w-5 h-5 text-indigo-600 dark:text-indigo-300" />
                      Settings
                    </h2>
                    <button onClick={() => setIsSettingsOpen(false)} className="p-1.5 rounded-full hover:bg-gray-200 dark:hover:bg-gray-700 transition-colors">
                      <X className="w-4 h-4 text-gray-500" />
                    </button>
                  </div>

                  <div className="space-y-3">
                    {/* Install App Button */}
                    {installPrompt && (
                      <button
                        onClick={handleInstallClick}
                        className="w-full flex items-center gap-3 p-3 rounded-xl bg-indigo-50 dark:bg-indigo-900/20 border border-transparent hover:border-indigo-200 dark:hover:border-indigo-800 transition-all group mb-3"
                      >
                         <div className="p-1.5 rounded-lg bg-indigo-100 dark:bg-indigo-800 text-indigo-600 dark:text-indigo-200">
                          <Smartphone size={18} />
                        </div>
                        <div className="text-left">
                          <p className="font-medium text-sm text-gray-900 dark:text-white">Install App</p>
                          <p className="text-[10px] text-gray-500 dark:text-gray-400">Add to Home Screen</p>
                        </div>
                      </button>
                    )}

                    <div className="space-y-2">
                      <p className="text-[10px] font-semibold text-gray-500 uppercase tracking-wider ml-1 mb-1">Data</p>

                      <button
                        onClick={handleExportData}
                        className="w-full flex items-center gap-3 p-2.5 rounded-xl hover:bg-gray-100 dark:hover:bg-gray-800 transition-colors"
                      >
                        <Download size={18} className="text-gray-500 dark:text-gray-400" />
                        <div className="text-left">
                          <p className="text-sm font-medium text-gray-900 dark:text-white">Export Bookmarks</p>
                        </div>
                      </button>

                      <button
                        onClick={handleImportClick}
                        className="w-full flex items-center gap-3 p-2.5 rounded-xl hover:bg-gray-100 dark:hover:bg-gray-800 transition-colors"
                      >
                        <Upload size={18} className="text-gray-500 dark:text-gray-400" />
                        <div className="text-left">
                          <p className="text-sm font-medium text-gray-900 dark:text-white">Import Bookmarks</p>
                        </div>
                        <input 
                          type="file" 
                          ref={fileInputRef}
                          onChange={handleImportFile}
                          className="hidden"
                          accept="application/json"
                        />
                      </button>

                      <button
                        onClick={handleClearAll}
                        className="w-full flex items-center gap-3 p-2.5 rounded-xl hover:bg-red-50 dark:hover:bg-red-900/10 text-red-600 dark:text-red-400 transition-colors mt-1"
                      >
                        <Trash2 size={18} />
                        <p className="text-sm font-medium">Clear All Data</p>
                      </button>
                    </div>
                  </div>

                </div>
              </div>
            </motion.div>
          </>
        )}
      </AnimatePresence>
    </div>
  );
}

export default App;

import React, { useState } from 'react';
import { motion } from 'framer-motion';
import { ExternalLink, Trash2, Globe, Edit2, Copy, Check, Share2, GripVertical, Folder, FolderOpen } from 'lucide-react';
import { useSortable } from '@dnd-kit/sortable';
import { CSS } from '@dnd-kit/utilities';
import { Bookmark } from '../types';
import { getFaviconUrl } from '../utils/helpers';

interface BookmarkCardProps {
  bookmark: Bookmark;
  onDelete: (id: string) => void;
  onEdit: (bookmark: Bookmark) => void;
  onNavigate?: (id: string) => void;
  isDragOverlay?: boolean;
}

const BookmarkCard: React.FC<BookmarkCardProps> = ({ bookmark, onDelete, onEdit, onNavigate, isDragOverlay = false }) => {
  const [imageError, setImageError] = useState(false);
  const [isCopied, setIsCopied] = useState(false);
  const isFolder = bookmark.type === 'folder';

  // dnd-kit hook
  const {
    attributes,
    listeners,
    setNodeRef,
    transform,
    transition,
    isDragging,
  } = useSortable({ id: bookmark.id, disabled: false });

  const style = {
    transform: CSS.Transform.toString(transform),
    transition,
    opacity: isDragging ? 0.4 : 1,
    zIndex: isDragging ? 50 : 'auto',
    touchAction: 'none', // Prevents scrolling when dragging via the handle
  };

  const copyToClipboard = () => {
    if (bookmark.url) {
      navigator.clipboard.writeText(bookmark.url).then(() => {
        setIsCopied(true);
        setTimeout(() => setIsCopied(false), 2000);
      }).catch(err => {
        console.error('Failed to copy: ', err);
      });
    }
  };

  const handleCopy = (e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();
    copyToClipboard();
  };

  const handleShare = async (e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();

    if (navigator.share && bookmark.url) {
      try {
        await navigator.share({
          title: bookmark.title,
          text: `Check out this link: ${bookmark.title}`,
          url: bookmark.url,
        });
      } catch (err) {
        console.log('Share canceled or failed:', err);
      }
    } else {
      copyToClipboard();
    }
  };

  const handleClick = (e: React.MouseEvent) => {
    if (isFolder && onNavigate) {
      e.preventDefault();
      onNavigate(bookmark.id);
    } else if (bookmark.url) {
      e.preventDefault();
      window.open(bookmark.url, '_blank', 'noopener,noreferrer');
    }
  };

  // If this is the "Ghost" overlay, we don't want the hook attributes/listeners on it again
  const cardProps = isDragOverlay ? {} : {
    ref: setNodeRef,
    style: style,
    ...attributes
  };

  return (
    <motion.div
      layout={!isDragging} // Disable layout animation while dragging to prevent fighting with DnD
      initial={isDragOverlay ? undefined : { opacity: 0, y: 20 }}
      animate={isDragOverlay ? undefined : { opacity: 1, y: 0 }}
      exit={{ opacity: 0, scale: 0.9 }}
      whileHover={isDragOverlay ? undefined : { y: -2 }}
      className={`group relative w-full ${isDragOverlay ? 'cursor-grabbing scale-105 z-50' : ''}`}
      {...cardProps}
    >
      {/* Material Card - Surface Container Low */}
      <div 
        onClick={handleClick}
        className={`
        relative overflow-hidden rounded-[16px]
        bg-m3-surfaceContainer-light dark:bg-m3-surfaceContainer-dark
        border border-gray-200 dark:border-gray-800
        transition-shadow duration-300
        h-full flex flex-col cursor-pointer
        ${isDragOverlay ? 'shadow-xl' : 'hover:shadow-md shadow-sm'}
      `}>
        {/* Ripple/State Layer on Hover */}
        {!isDragOverlay && (
          <div className="absolute inset-0 bg-current opacity-0 hover:opacity-[0.08] dark:hover:opacity-[0.08] transition-opacity duration-200 pointer-events-none text-indigo-900 dark:text-indigo-100" />
        )}

        <div className="p-3 flex flex-col h-full z-10 relative">
          <div className="flex items-start justify-between mb-2">
            <div className="flex items-center gap-2">
              {/* Drag Handle */}
              {!isDragOverlay && (
                 <div 
                  {...listeners}
                  onClick={(e) => e.stopPropagation()} 
                  className="cursor-grab active:cursor-grabbing p-1 -ml-1.5 rounded-full text-gray-500 hover:bg-gray-200 dark:text-gray-500 dark:hover:bg-gray-700 transition-colors"
                  title="Drag to reorder"
                >
                  <GripVertical size={16} />
                </div>
              )}

              <div className={`flex items-center justify-center w-8 h-8 rounded-lg shadow-sm border ${isFolder ? 'bg-indigo-100 dark:bg-indigo-900/30 border-indigo-200 dark:border-indigo-800' : 'bg-white dark:bg-gray-800 border-gray-100 dark:border-gray-700'}`}>
                {isFolder ? (
                  <Folder className="w-4 h-4 text-indigo-600 dark:text-indigo-400" />
                ) : (
                  !imageError ? (
                    <img 
                      src={getFaviconUrl(bookmark.domain || '')} 
                      alt={bookmark.title}
                      className="w-4 h-4 object-contain"
                      onError={() => setImageError(true)}
                    />
                  ) : (
                    <Globe className="w-4 h-4 text-gray-500 dark:text-gray-400" />
                  )
                )}
              </div>
            </div>

            <div className="flex items-center" onClick={(e) => e.stopPropagation()}>
              {/* Actions */}
              {!isFolder && (
                <>
                  <motion.button
                    whileHover={{ scale: 1.1 }}
                    whileTap={{ scale: 0.9 }}
                    onClick={handleShare}
                    className="p-1.5 rounded-full hover:bg-gray-200 dark:hover:bg-gray-700 text-gray-400 dark:text-gray-500 hover:text-gray-600 dark:hover:text-gray-300 transition-colors"
                    title="Share"
                  >
                    <Share2 size={14} />
                  </motion.button>

                  <motion.button
                    whileHover={{ scale: 1.1 }}
                    whileTap={{ scale: 0.9 }}
                    onClick={handleCopy}
                    className="p-1.5 rounded-full hover:bg-gray-200 dark:hover:bg-gray-700 text-gray-400 dark:text-gray-500 hover:text-gray-600 dark:hover:text-gray-300 transition-colors"
                    title={isCopied ? "Copied!" : "Copy Link"}
                  >
                    {isCopied ? <Check size={14} className="text-emerald-600" /> : <Copy size={14} />}
                  </motion.button>
                </>
              )}

              <motion.button
                whileHover={{ scale: 1.1 }}
                whileTap={{ scale: 0.9 }}
                onClick={(e) => {
                  e.preventDefault();
                  e.stopPropagation();
                  onEdit(bookmark);
                }}
                className="p-1.5 rounded-full hover:bg-gray-200 dark:hover:bg-gray-700 text-gray-400 dark:text-gray-500 hover:text-gray-600 dark:hover:text-gray-300 transition-colors"
                title="Edit"
              >
                <Edit2 size={14} />
              </motion.button>

              <motion.button
                whileHover={{ scale: 1.1 }}
                whileTap={{ scale: 0.9 }}
                onClick={(e) => {
                  e.preventDefault();
                  e.stopPropagation();
                  onDelete(bookmark.id);
                }}
                className="p-1.5 rounded-full hover:bg-red-50 dark:hover:bg-red-900/20 text-gray-400 hover:text-red-600 dark:text-gray-500 dark:hover:text-red-400 transition-colors"
                title="Delete"
              >
                <Trash2 size={14} />
              </motion.button>
            </div>
          </div>

          <div className="flex-grow min-w-0">
            <h3 className="text-sm font-medium text-gray-900 dark:text-gray-200 mb-0.5 line-clamp-2 leading-snug">
              {bookmark.title || bookmark.domain}
            </h3>
            {!isFolder && (
              <>
                <div className="flex items-center gap-1.5 mb-0.5">
                  <span className="text-[10px] font-medium px-1.5 py-0.5 rounded bg-indigo-50 text-indigo-700 dark:bg-indigo-900/30 dark:text-indigo-300">
                    {bookmark.category}
                  </span>
                </div>
                <p className="text-xs text-gray-500 dark:text-gray-500 truncate">
                  {bookmark.domain}
                </p>
              </>
            )}
            {isFolder && (
               <p className="text-xs text-gray-500 dark:text-gray-500 truncate">
                 Folder
               </p>
            )}
          </div>

          <div className="mt-3 pt-2 border-t border-gray-200 dark:border-gray-800 flex justify-end">
            <motion.button 
              whileHover={{ scale: 1.02 }}
              whileTap={{ scale: 0.98 }}
              onClick={handleClick}
              className={`
                flex items-center space-x-1.5 px-3 py-1.5 rounded-full
                ${isFolder 
                  ? 'bg-gray-100 dark:bg-gray-800 text-gray-900 dark:text-gray-300 hover:bg-gray-200 dark:hover:bg-gray-700' 
                  : 'bg-indigo-600 dark:bg-indigo-700 text-white dark:text-indigo-100 hover:bg-indigo-700 dark:hover:bg-indigo-600'}
                font-medium text-xs transition-colors shadow-sm
              `}
            >
              <span>{isFolder ? 'Open' : 'Visit'}</span>
              {isFolder ? <FolderOpen size={12} /> : <ExternalLink size={12} />}
            </motion.button>
          </div>
        </div>
      </div>
    </motion.div>
  );
};

